const Web3 = require('web3');
const ethers = require('ethers');

// Wallet configuration with private keys for signing transactions
const walletConfig = {
  privateKey1: '0x...private key 1...',
  privateKey2: '0x...private key 2...',
};

class EthereumService {
  constructor() {
    this.web3 = new Web3(new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_PROJECT_ID'));
    this.ethers = ethers;
  }

  async sendEth(recipient, amount) {
    try {
      const wallet = new this.ethers.Wallet(walletConfig.privateKey1);
      const transaction = await wallet.sendTransaction({
        to: recipient,
        value: this.ethers.utils.parseUnits(amount.toString(), 'ether'),
      });
      return transaction.hash;
    } catch (error) {
      console.error('Error sending ETH:', error);
      throw error;
    }
  }

  async interactWithContract(contractAddress, contractAbi, functionName, ...args) {
    try {
      const wallet = new this.ethers.Wallet(walletConfig.privateKey1);
      const contract = new this.ethers.Contract(contractAddress, contractAbi);
      const transaction = await contract.functions[functionName](...args).send({
        from: wallet.address,
        gasLimit: 2000000,
      });
      return transaction.hash;
    } catch (error) {
      console.error('Error interacting with contract:', error);
      throw error;
    }
  }

  async validateInput(input) {
    if (!input || typeof input !== 'string') {
      throw new Error('Invalid input');
    }
    try {
      const web3 = new Web3(new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_PROJECT_ID'));
      await web3.eth.getCode(input);
    } catch (error) {
      if (error.code === -32603 && error.data.message.includes('unknown account')) {
        throw new Error('Invalid Ethereum address');
      }
      throw error;
    }
  }

  async getBalance(address) {
    try {
      const balance = await this.web3.eth.getBalance(address);
      return this.ethers.utils.formatEther(balance);
    } catch (error) {
      console.error('Error getting balance:', error);
      throw error;
    }
  }
}

module.exports = EthereumService;